package com.hospital.management.service.impl;import com.hospital.management.dao.*;import com.hospital.management.model.*;import org.junit.jupiter.api.*;import org.junit.jupiter.api.extension.ExtendWith;import org.mockito.*;import org.mockito.junit.jupiter.MockitoExtension;import java.time.*;import java.util.*;import static org.junit.jupiter.api.Assertions.*;import static org.mockito.Mockito.*;
@ExtendWith(MockitoExtension.class)class AppointmentAvailabilityDayTest {private static final Clock CLOCK=Clock.fixed(Instant.parse("2026-07-26T06:30:00Z"),ZoneId.of("Asia/Kolkata"));@Mock DoctorScheduleDao schedules;@Mock AppointmentDao appointments;@Mock DoctorDao doctors;AppointmentAvailabilityServiceImpl service;@BeforeEach void setUp()throws Exception{service=new AppointmentAvailabilityServiceImpl(schedules,appointments,doctors,CLOCK);Doctor d=new Doctor();d.setDoctorId(9L);d.setStatus("ACTIVE");d.setUserStatus("ACTIVE");lenient().when(doctors.findById(9L)).thenReturn(Optional.of(d));lenient().when(appointments.findBookedStartTimes(eq(9L),any())).thenReturn(List.of());}
@Test void mondayScheduleReturnsExpectedFiftyMinuteSlots()throws Exception{LocalDate monday=LocalDate.of(2026,7,27);when(schedules.findAvailableByDoctorAndDay(9L,"MONDAY")).thenReturn(List.of(window(LocalTime.of(10,0),LocalTime.of(15,0),50)));List<AvailableSlot>x=service.getAvailableSlots(9L,monday,null);assertEquals(List.of("10:00","10:50","11:40","12:30","13:20","14:10"),x.stream().map(s->s.getStartTime().toString()).toList());}
@Test void thursdayWithoutScheduleReturnsEmpty()throws Exception{LocalDate thursday=LocalDate.of(2026,7,30);when(schedules.findAvailableByDoctorAndDay(9L,"THURSDAY")).thenReturn(List.of());assertTrue(service.getAvailableSlots(9L,thursday,null).isEmpty());}
@Test void bookedSlotIsExcluded()throws Exception{LocalDate monday=LocalDate.of(2026,7,27);when(schedules.findAvailableByDoctorAndDay(9L,"MONDAY")).thenReturn(List.of(window(LocalTime.of(10,0),LocalTime.of(12,30),50)));when(appointments.findBookedStartTimes(9L,monday)).thenReturn(List.of(LocalTime.of(10,50)));assertEquals(List.of(LocalTime.of(10,0),LocalTime.of(11,40)),service.getAvailableSlots(9L,monday,null).stream().map(AvailableSlot::getStartTime).toList());}
@Test void futureDateMorningSlotsAreNotRemovedAsPast()throws Exception{LocalDate monday=LocalDate.of(2026,7,27);when(schedules.findAvailableByDoctorAndDay(9L,"MONDAY")).thenReturn(List.of(window(LocalTime.of(8,0),LocalTime.of(9,0),30)));assertEquals(2,service.getAvailableSlots(9L,monday,null).size());}
@Test void todaysPastSlotsAreRemoved()throws Exception{LocalDate today=LocalDate.of(2026,7,26);when(schedules.findAvailableByDoctorAndDay(9L,"SUNDAY")).thenReturn(List.of(window(LocalTime.of(10,0),LocalTime.of(14,10),50)));assertEquals(List.of(LocalTime.of(12,30),LocalTime.of(13,20)),service.getAvailableSlots(9L,today,null).stream().map(AvailableSlot::getStartTime).toList());}
private DoctorSchedule window(LocalTime start,LocalTime end,int duration){DoctorSchedule s=new DoctorSchedule();s.setStartTime(start);s.setEndTime(end);s.setSlotDurationMinutes(duration);s.setAvailable(true);return s;}}
